} from './TaggerOutput.js';

export interface CreateTagPromptPassDeps {
  llmClient: LlmClient;
  model?: string;
}

export interface MaterializeSpansResult {
  output: MaterializedTaggerOutput;
  diagnostics: PassDiagnostic[];
}

let _cachedTagPromptSystemPrompt: string | null = null;

export function getTagPromptSystemPrompt(): string {
  if (_cachedTagPromptSystemPrompt === null) {
    _cachedTagPromptSystemPrompt = renderPromptTemplate('chatbot-compile.tagger.system');
  }
  return _cachedTagPromptSystemPrompt;
}

export function reloadTagPromptSystemPromptForTests(): void {
  _cachedTagPromptSystemPrompt = null;
}

export function parseRawTaggerOutput(raw: string, pass_id = 'tag_prompt'): {
  output: RawTaggerOutput;
  diagnostics: PassDiagnostic[];
} {
  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    return {
      output: { tags: [] },
      diagnostics: [{
        severity: 'warning',
        code: 'tag_prompt_parse_error',
        message: `tag_prompt response was not valid JSON: ${err instanceof Error ? err.message : String(err)}`,
        pass_id,
        details: { raw_preview: raw.slice(0, 300) },
      }],
    };
  }

  const result = RawTaggerOutputSchema.safeParse(parsed);
  if (!result.success) {
    return {
      output: { tags: [] },
      diagnostics: [{
        severity: 'warning',
        code: 'tag_prompt_shape_mismatch',
        message: 'tag_prompt output shape mismatch',
        pass_id,
        details: { issues: result.error.issues.slice(0, 5) },
      }],
    };
  }

  return { output: result.data, diagnostics: [] };
}

export function materializeSpans(
  prompt: string,
  raw: RawTaggerOutput,
  pass_id = 'tag_prompt',
): MaterializeSpansResult {
  const diagnostics: PassDiagnostic[] = [];
  const tags: MaterializedPromptTag[] = [];

  for (const tag of raw.tags) {
    const matches = findOccurrences(prompt, tag.text);
    if (matches.length === 0) {
      diagnostics.push(spanDiagnostic('tag_prompt_span_not_found', tag, pass_id));
      continue;
    }

    const occurrence = tag.nthOccurrence;
    if (occurrence === undefined && matches.length > 1) {
      diagnostics.push(spanDiagnostic('tag_prompt_span_ambiguous', tag, pass_id, {
        occurrences: matches.length,
      }));
      continue;
    }

    const index = occurrence === undefined ? 0 : occurrence - 1;
    const span = matches[index];
    if (!span) {
      diagnostics.push(spanDiagnostic('tag_prompt_span_not_found', tag, pass_id, {
        requestedOccurrence: occurrence,
        occurrences: matches.length,
      }));
      continue;
    }

    if (prompt.slice(span[0], span[1]) !== tag.text) {
      diagnostics.push(spanDiagnostic('tag_prompt_span_roundtrip_failed', tag, pass_id, { span }));
      continue;
    }

    tags.push({ ...tag, span });
  }

  return { output: { tags }, diagnostics };
}

export function createTagPromptPass(deps: CreateTagPromptPassDeps): Pass {
  return {
    id: 'tag_prompt',
    family: 'parse' as const,
    async run({ pass_id, state }): Promise<PassResult> {
      const prompt = typeof state.input.prompt === 'string' ? state.input.prompt : '';
      if (prompt.trim().length === 0) {
        return { ok: true, output: { tags: [] } satisfies MaterializedTaggerOutput };
      }

      const mentions = Array.isArray(state.input.mentions) ? state.input.mentions : [];
      if (mentions.length > 0) {
        return {
          ok: true,
          output: { tags: [] } satisfies MaterializedTaggerOutput,
          diagnostics: [{
            severity: 'info',
            code: 'tag_prompt_skipped_for_resolved_mentions',
            message: 'Resolved prompt mentions are present; deterministic precompile will use the raw prompt path.',
            pass_id,
          }],
        };
      }

      const messages: ChatMessage[] = [
        { role: 'system', content: getTagPromptSystemPrompt() },
        { role: 'user', content: JSON.stringify({ prompt }) },
      ];
      let response: Awaited<ReturnType<LlmClient['complete']>>;
      try {
        response = await deps.llmClient.complete({
          model: deps.model ?? 'claude-sonnet-4-6',
          messages,
          response_format: { type: 'json_object' },
        } as CompletionRequest);
      } catch (err) {
        return {
          ok: true,
          output: { tags: [] } satisfies MaterializedTaggerOutput,
          diagnostics: [{
            severity: 'warning',
            code: 'tag_prompt_llm_error',
            message: `tag_prompt LLM call failed: ${err instanceof Error ? err.message : String(err)}`,
            pass_id,
          }],
        };
      }

      const raw = response.choices[0]?.message?.content ?? '';
      const parsed = parseRawTaggerOutput(raw, pass_id);
      const materialized = materializeSpans(prompt, parsed.output, pass_id);

      return {
        ok: true,
        output: materialized.output,
        diagnostics: [...parsed.diagnostics, ...materialized.diagnostics],
      };
    },
  };
}

function findOccurrences(text: string, needle: string): Array<[number, number]> {
  const spans: Array<[number, number]> = [];
  if (needle.length === 0) return spans;

  let cursor = 0;
  while (cursor <= text.length) {
    const start = text.indexOf(needle, cursor);
    if (start === -1) break;
    spans.push([start, start + needle.length]);
    cursor = start + needle.length;
  }
  return spans;
}

function spanDiagnostic(
  code: string,
  tag: RawPromptTag,
  pass_id: string,
  details: Record<string, unknown> = {},
): PassDiagnostic {
  return {
    severity: 'warning',
    code,
    message: `Could not materialize ${tag.kind} tag "${tag.text}"`,
    pass_id,
    details: {
      kind: tag.kind,
      text: tag.text,
      ...(tag.nthOccurrence !== undefined ? { nthOccurrence: tag.nthOccurrence } : {}),
      ...details,
    },
  };
}

/**
 * ParameterGrammar — deterministic regex extractors for volumes, counts,
 * well addresses, and durations from clause text.
 *
 * Pure functions, no side effects, no async. All extractors return [] for
 * empty input and never throw. Spans are character offsets into the input;
 * round-trip (text.slice(span[0], span[1]) === raw) holds.
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface VolumeMatch {
  value: number;
  unit: 'uL';
  span: [number, number];
  raw: string;
}

export interface CountMatch {
  value: number;
  span: [number, number];
  raw: string;
}

export interface WellMatch {
  wells: string[];
  kind: 'single' | 'range' | 'row' | 'col' | 'list';
  span: [number, number];
  raw: string;
}

export interface DurationMatch {
  value_seconds: number;
  span: [number, number];
  raw: string;
}

// ---------------------------------------------------------------------------
// English number word → digit map
// ---------------------------------------------------------------------------

const ENGLISH_WORDS: Record<string, number> = {
  one: 1,
  two: 2,
  three: 3,
  four: 4,
  five: 5,
  six: 6,
  seven: 7,
  eight: 8,
  nine: 9,
  ten: 10,
  eleven: 11,
  twelve: 12,
};

// ---------------------------------------------------------------------------
// extractVolumes
// ---------------------------------------------------------------------------

/**
 * Extract volume quantities from text. Normalises all units to uL.
 *
 * Matches: µL, μL, uL, microliter, microliters, mL, ml, milliliter,
 *          milliliters, L, l, liter, liters
 *
 * Conversion: uL/microliter → ×1; mL/milliliter → ×1000; L/liter → ×1_000_000.
 */
export function extractVolumes(text: string): VolumeMatch[] {
  if (typeof text !== 'string' || text.length === 0) return [];

  // Match both U+00B5 (µ) and U+03BC (μ, Greek lowercase mu)
  const re = /(\d+(?:\.\d+)?)\s*([µμ]L|uL|microliters?|mL|ml|milliliters?|L|liters?)\b/gi;
  const results: VolumeMatch[] = [];
  let m: RegExpExecArray | null;

  while ((m = re.exec(text)) !== null) {
    const value = parseFloat(m[1]!);
    const unitRaw = m[2]!.toLowerCase();
    let multiplier = 1;

    if (unitRaw === 'ml' || unitRaw === 'milliliter' || unitRaw === 'milliliters') {
      multiplier = 1000;
    } else if (unitRaw === 'l' || unitRaw === 'liter' || unitRaw === 'liters') {
      multiplier = 1_000_000;
    }

    results.push({
      value: value * multiplier,
      unit: 'uL',
      span: [m.index, m.index + m[0].length],
      raw: m[0],
    });
  }

  return results;
}

// ---------------------------------------------------------------------------
// extractCounts
// ---------------------------------------------------------------------------

/**
 * Extract count quantities from text. Accepts decimal digits and English
 * number words 'one' through 'twelve' (case-insensitive).
 */
export function extractCounts(text: string): CountMatch[] {
  if (typeof text !== 'string' || text.length === 0) return [];

  const results: CountMatch[] = [];

  // --- Digit matches ---
  const digitRe = /\b(\d+)\b/g;
  let m: RegExpExecArray | null;
  while ((m = digitRe.exec(text)) !== null) {
    results.push({
      value: parseInt(m[1]!, 10),
      span: [m.index, m.index + m[0].length],
      raw: m[0],
    });
  }

  // --- English word matches ---
  const wordRe = /\b(one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve)\b/gi;
  while ((m = wordRe.exec(text)) !== null) {
    const wordKey = m[1]!.toLowerCase();
    const wordValue = ENGLISH_WORDS[wordKey];
    if (wordValue === undefined) continue; // safety, should never happen
    results.push({
      value: wordValue,
      span: [m.index, m.index + m[0].length],
      raw: m[0],
    });
  }

  // Sort by span start for deterministic output
  results.sort((a, b) => a.span[0] - b.span[0]);

  return results;
}

// ---------------------------------------------------------------------------
// extractWellAddresses
// ---------------------------------------------------------------------------

/**
 * Extract well-address references from text.
 *
 * Patterns:
 *   - Single cell:  A1, H12
 *   - Range:        A1-A12, A1–A6 (em-dash also)
 *   - Row label:    row B
 *   - Column label: column 3, col C
 *   - List:         wells A1, A3, A5
 */
export function extractWellAddresses(text: string): WellMatch[] {
  if (typeof text !== 'string' || text.length === 0) return [];

  const results: WellMatch[] = [];

  // --- List pattern (must be checked before single/range to avoid partial matches) ---
  const listRe = /\bwells?\s+([A-H]\d{1,2}(?:\s*,\s*[A-H]\d{1,2})+)\b/gi;
  let m: RegExpExecArray | null;
  while ((m = listRe.exec(text)) !== null) {
    const inner = m[1]!;
    const wells = inner.split(/\s*,\s*/).map((w) => w.trim());
    results.push({
      wells,
      kind: 'list',
      span: [m.index, m.index + m[0].length],
      raw: m[0],
    });
  }

  // --- Row label pattern ---
  const rowRe = /\brow\s+([A-H])\b/gi;
  while ((m = rowRe.exec(text)) !== null) {
    const row = m[1]!.toUpperCase();
    const wells: string[] = [];
    for (let col = 1; col <= 12; col++) {
      wells.push(`${row}${col}`);
    }
    results.push({
      wells,
      kind: 'row',
      span: [m.index, m.index + m[0].length],
      raw: m[0],
    });
  }

  // --- Column label pattern ---
  const colRe = /\b(?:col|column)\s+(\d{1,2})\b/gi;
  while ((m = colRe.exec(text)) !== null) {
    const colNum = parseInt(m[1]!, 10);
    const wells: string[] = [];
    for (let row = 0; row < 8; row++) {
      wells.push(`${String.fromCharCode(65 + row)}${colNum}`);
    }
    results.push({
      wells,
      kind: 'col',
      span: [m.index, m.index + m[0].length],
      raw: m[0],
    });
  }

  // --- Range pattern (em-dash and hyphen) ---
  const rangeRe = /\b([A-H])(\d{1,2})\s*[-–]\s*([A-H])(\d{1,2})\b/g;
  while ((m = rangeRe.exec(text)) !== null) {
    const row1 = m[1]!.toUpperCase();
    const col1 = parseInt(m[2]!, 10);
    const row2 = m[3]!.toUpperCase();
    const col2 = parseInt(m[4]!, 10);

    const wells: string[] = [];

    if (row1 === row2) {
      // Same row: expand columns
      const start = Math.min(col1, col2);
      const end = Math.max(col1, col2);
      for (let c = start; c <= end; c++) {
        wells.push(`${row1}${c}`);
      }
    } else if (col1 === col2) {
      // Same column: expand rows
      const rowStart = Math.min(row1.charCodeAt(0), row2.charCodeAt(0));
      const rowEnd = Math.max(row1.charCodeAt(0), row2.charCodeAt(0));
      for (let r = rowStart; r <= rowEnd; r++) {
        wells.push(`${String.fromCharCode(r)}${col1}`);
      }
    } else {
      // Different row AND column: bounding-rect reading order
      const rowStart = Math.min(row1.charCodeAt(0), row2.charCodeAt(0));
      const rowEnd = Math.max(row1.charCodeAt(0), row2.charCodeAt(0));
      const colStart = Math.min(col1, col2);
      const colEnd = Math.max(col1, col2);
      for (let r = rowStart; r <= rowEnd; r++) {
        for (let c = colStart; c <= colEnd; c++) {
          wells.push(`${String.fromCharCode(r)}${c}`);
        }
      }
    }

    results.push({
      wells,
      kind: 'range',
      span: [m.index, m.index + m[0].length],
      raw: m[0],
    });
  }

  // --- Single-cell pattern ---
  const singleRe = /\b([A-H])(\d{1,2})\b/g;
  while ((m = singleRe.exec(text)) !== null) {
    const raw = m[0];
    // Skip if this cell is part of a range or list match we already captured
    const isInRange = results.some(
      (r) => (r.kind === 'range' || r.kind === 'list') && r.raw.includes(raw),
    );
    if (isInRange) continue;

    results.push({
      wells: [raw],
      kind: 'single',
      span: [m.index, m.index + m[0].length],
      raw,
    });
  }

  // Sort by span start for deterministic output
  results.sort((a, b) => a.span[0] - b.span[0]);

  return results;
}

// ---------------------------------------------------------------------------
// extractDurations
// ---------------------------------------------------------------------------

/**
 * Extract duration quantities from text. Converts all units to seconds.
 *
 * Matches: N s/sec/seconds, N min/minutes, N h/hr/hours, N day/days
 * Special token: overnight → 43200 seconds (12 hours)
 */
export function extractDurations(text: string): DurationMatch[] {
  if (typeof text !== 'string' || text.length === 0) return [];

  const results: DurationMatch[] = [];

  // --- Numeric duration pattern ---
  const re = /(\d+(?:\.\d+)?)\s*(s|sec|seconds?|min|minutes?|h|hr|hours?|days?)\b/gi;
  let m: RegExpExecArray | null;
  while ((m = re.exec(text)) !== null) {
    const value = parseFloat(m[1]!);
    const unit = m[2]!.toLowerCase();
    let multiplier = 1;

    if (unit === 'min' || unit === 'minute' || unit === 'minutes') {
      multiplier = 60;
    } else if (unit === 'h' || unit === 'hr' || unit === 'hour' || unit === 'hours') {
      multiplier = 3600;
    } else if (unit === 'day' || unit === 'days') {
      multiplier = 86400;
    }

    results.push({
      value_seconds: value * multiplier,
      span: [m.index, m.index + m[0].length],
      raw: m[0],
    });
  }

  // --- Overnight special token ---
  const overnightRe = /\bovernight\b/gi;
  while ((m = overnightRe.exec(text)) !== null) {
    results.push({
      value_seconds: 12 * 3600, // 43200
      span: [m.index, m.index + m[0].length],
      raw: m[0],
    });
  }

  // Sort by span start for deterministic output
  results.sort((a, b) => a.span[0] - b.span[0]);

  return results;
}

/**
 * Fix-it fixture discovery test.
 *
 * Scans this directory for `spec-fix-*.yaml` files and runs each one
 * through the deterministic precompile via FixtureRunner. New fix-it
 * sessions land their failing-prompt fixture here as part of the spec
 * synthesis step; the coder agent must make all of them pass before
 * its patch is committed.
 *
 * Run a specific fixture with:
 *   npx vitest run server/src/compiler/pipeline/fixtures/FixItFixtures.test.ts -t '<fixture-name>'
 */

import { describe, expect, it } from 'vitest';
import { readdirSync, readFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { parseFixture } from './FixtureTypes.js';
import { runFixture } from './FixtureRunner.js';
import { diffFixture } from './FixtureDiff.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const SPEC_FIX_PATTERN = /^spec-fix-.+\.yaml$/;

const fixtureFiles = readdirSync(__dirname)
  .filter((name) => SPEC_FIX_PATTERN.test(name))
  .sort();

// If there are no fix-it fixtures yet, the suite still defines a single test
// so it's discoverable in CI output. (vitest dislikes empty describe blocks.)
describe('FixItFixtures', () => {
  if (fixtureFiles.length === 0) {
    it('no spec-fix-*.yaml fixtures yet (this is fine; nothing to run)', () => {
      expect(true).toBe(true);
    });
    return;
  }

  for (const fileName of fixtureFiles) {
    const yamlText = readFileSync(join(__dirname, fileName), 'utf-8');
    const fixture = parseFixture(yamlText);

    // The test name == fixture name so the coder agent can target a single
    // fixture from the spec via `-t '<fixture-name>'`.
    it(fixture.name, async () => {
      const result = await runFixture(fixture);
      const diff = diffFixture(result, fixture.expected);
      // Missing keys = expected fields the actual output doesn't have.
      // Treat any missing as a hard fail; partial/extra are advisory.
      expect(diff.missing, `missing keys: ${diff.missing.join(', ')}`).toEqual([]);
    });
  }
});

/**
 * FixtureRunner - Runs a compile pipeline with a mocked LLM.
 *
 * The runner builds a mock LlmClient that returns the fixture's pinned
 * ai_precompile output verbatim, then invokes runChatbotCompile and
 * collects the actual TerminalArtifacts.
 */

import type { LlmClient, AiPrecompileOutput } from '../passes/ChatbotCompilePasses.js';
import type { CompletionRequest, CompletionResponse } from '../../../ai/types.js';
import type { RunChatbotCompileArgs, RunChatbotCompileResult } from '../../../ai/runChatbotCompile.js';
import { runChatbotCompile } from '../../../ai/runChatbotCompile.js';
import type { Fixture, FixtureResult } from './FixtureTypes.js';
import type { ExtractionRunnerService, RunExtractionServiceArgs } from '../../../extract/ExtractionRunnerService.js';
import type { ExtractionDraftBody } from '../../../extract/ExtractionDraftBuilder.js';
import type { FileAttachment } from '../../../ai/types.js';

// Ensure pattern expanders are registered (side-effect import)
import '../../../compiler/patterns/index.js';

// ---------------------------------------------------------------------------
// buildTestDeps — minimal stubs for non-LLM dependencies
// ---------------------------------------------------------------------------

/**
 * Build a minimal ExtractionRunnerService stub that returns empty results.
 */
function buildTestExtractionService(): ExtractionRunnerService {
  return {
    run: async (_req: RunExtractionServiceArgs): Promise<ExtractionDraftBody> => ({
      target_kind: _req.target_kind,
      source: _req.source,
      candidates: [],
      diagnostics: [],
    }),
  } as unknown as ExtractionRunnerService;
}

/**
 * Build a minimal searchLabwareByHint stub that returns no matches.
 */
function buildTestSearchLabwareByHint() {
  return async (_hint: string): Promise<Array<{ recordId: string; title: string }>> => [];
}

// ---------------------------------------------------------------------------
// buildMockLlmClient — create an LlmClient that returns the pinned output
// ---------------------------------------------------------------------------

function buildMockLlmClient(mockedOutput: AiPrecompileOutput): LlmClient {
  return {
    complete: async (_req: CompletionRequest): Promise<CompletionResponse> => {
      const content = JSON.stringify(mockedOutput);
      return {
        id: 'fixture-mock',
        choices: [
          {
            index: 0,
            message: { role: 'assistant', content },
            finish_reason: 'stop',
          },
        ],
        usage: { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 },
      };
    },
  };
}

// ---------------------------------------------------------------------------
// runFixture — execute a fixture with mocked LLM
// ---------------------------------------------------------------------------

export async function runFixture(
  fixture: Fixture,
  opts?: {
    deps?: Partial<RunChatbotCompileArgs['deps']>;
    conversationId?: string;
  },
): Promise<FixtureResult> {
  // Deterministic-only fixtures don't have a mocked LLM output — the
  // deterministic precompile is the unit under test, so the LLM is fully
  // bypassed. The fixture validator already enforces that mocked_ai_precompile_output
  // is present for non-deterministic fixtures.
  const deterministicOnly = fixture.deterministicOnly === true;
  const llmClient: LlmClient | null = opts?.deps?.llmClient
    ?? (deterministicOnly
      ? null
      : buildMockLlmClient(fixture.mocked_ai_precompile_output!));

  const attachments = fixture.input.attachments?.map((a) => ({
    name: a.filename,
    mime_type: a.mimeType,
    content: a.content,
  }));
  const conversationId = opts?.conversationId ?? fixture.input.conversationId;

  const args: RunChatbotCompileArgs = {
    prompt: fixture.input.prompt,
    ...(attachments ? { attachments } : {}),
    ...(conversationId ? { conversationId } : {}),
    ...(deterministicOnly ? { deterministicOnly: true } : {}),
    deps: {
      extractionService: buildTestExtractionService(),
      llmClient,
      searchLabwareByHint: opts?.deps?.searchLabwareByHint ?? buildTestSearchLabwareByHint(),
      ...(opts?.deps?.labStateCache ? { labStateCache: opts.deps.labStateCache } : {}),
    },
  };

  const result: RunChatbotCompileResult = await runChatbotCompile(args);

  return {
    outcome: result.outcome,
    terminalArtifacts: result.terminalArtifacts,
    raw: result,
  };
}

/**
 * FixtureTypes - Type definitions and YAML parser for compile-pipeline fixtures.
 *
 * A fixture pins both the input (prompt, attachments, history) and the
 * expected output (outcome, terminalArtifacts) of a compile run.  The
 * mocked_ai_precompile_output field lets the runner bypass the LLM
 * entirely and feed a deterministic candidate-event graph into the
 * pipeline.
 */

import { parse as parseYaml } from 'yaml';
import type { TerminalArtifacts, CompileOutcome } from '../CompileContracts.js';
import type { AiPrecompileOutput } from '../passes/ChatbotCompilePasses.js';

// ---------------------------------------------------------------------------
// FixtureInput — what the user sends to the compile
// ---------------------------------------------------------------------------

export interface FixtureInput {
  prompt: string;
  attachments?: Array<{ filename: string; mimeType: string; content: string }>;
  history?: Array<{ role: 'user' | 'assistant'; content: string }>;
  conversationId?: string;
}

// ---------------------------------------------------------------------------
// FixtureExpected — what we assert the compile produced
// ---------------------------------------------------------------------------

export interface FixtureExpected {
  outcome?: CompileOutcome;
  terminalArtifacts?: Partial<TerminalArtifacts>;
}

// ---------------------------------------------------------------------------
// Fixture — the full fixture document
// ---------------------------------------------------------------------------

export interface Fixture {
  name: string;
  description?: string;
  input: FixtureInput;
  /**
   * Replaces the LLM-backed ai_precompile pass with these candidate
   * events/labwares. Required when `deterministicOnly` is false or absent —
   * skipped when `deterministicOnly: true` (the deterministic precompile
   * does the work).
   */
  mocked_ai_precompile_output?: AiPrecompileOutput;
  /**
   * When true, the runner sets deterministicOnly on runChatbotCompile so the
   * deterministic precompile is the only source of candidate events/labwares.
   * Used by event-editor fix-it fixtures that capture "this prompt should
   * produce that ghost preview without any LLM in the loop."
   */
  deterministicOnly?: boolean;
  expected: FixtureExpected;
}

// ---------------------------------------------------------------------------
// FixtureResult — what the runner produces
// ---------------------------------------------------------------------------

export interface FixtureResult {
  outcome: CompileOutcome;
  terminalArtifacts: TerminalArtifacts;
  raw: unknown; // full RunChatbotCompileResult for debugging
}

// ---------------------------------------------------------------------------
// FixtureDiff — structural comparison result
// ---------------------------------------------------------------------------

export interface FixtureDiff {
  matched: string[];
  partial: string[];
  missing: string[];
  extra: string[];
}

// ---------------------------------------------------------------------------
// parseFixture — load a Fixture from YAML text
// ---------------------------------------------------------------------------

/**
 * Parse a YAML string into a Fixture, performing basic shape validation.
 *
 * @param yamlText — raw YAML document
 * @returns the parsed Fixture
 * @throws Error if the YAML is invalid or the shape doesn't match
 */
export function parseFixture(yamlText: string): Fixture {
  const raw = parseYaml(yamlText);

  if (typeof raw !== 'object' || raw === null) {
    throw new Error('Fixture YAML must be a mapping');
  }

  const obj = raw as Record<string, unknown>;

  // Validate required fields
  if (typeof obj.name !== 'string' || obj.name.trim() === '') {
    throw new Error('Fixture must have a non-empty "name" string');
  }

  if (typeof obj.input !== 'object' || obj.input === null) {
    throw new Error('Fixture must have an "input" mapping');
  }

  const input = obj.input as Record<string, unknown>;
  if (typeof input.prompt !== 'string' || input.prompt.trim() === '') {
    throw new Error('Fixture input must have a non-empty "prompt" string');
  }

  const deterministicOnly = obj.deterministicOnly === true;

  if (!deterministicOnly) {
    if (typeof obj.mocked_ai_precompile_output !== 'object' || obj.mocked_ai_precompile_output === null) {
      throw new Error('Fixture must have a "mocked_ai_precompile_output" mapping (omit only when deterministicOnly: true)');
    }
  }

  if (typeof obj.expected !== 'object' || obj.expected === null) {
    throw new Error('Fixture must have an "expected" mapping');
  }

  return {
    name: obj.name as string,
    description: typeof obj.description === 'string' ? obj.description : undefined,
    input: {
      prompt: input.prompt as string,
      attachments: Array.isArray(input.attachments)
        ? (input.attachments as Array<Record<string, unknown>>).map((a) => ({
            filename: (a.filename as string) ?? '',
            mimeType: (a.mimeType as string) ?? '',
            content: (a.content as string) ?? '',
          }))
        : undefined,
      history: Array.isArray(input.history)
        ? (input.history as Array<Record<string, unknown>>).map((h) => ({
            role: (h.role as 'user' | 'assistant') ?? 'user',
            content: (h.content as string) ?? '',
          }))
        : undefined,
      conversationId: typeof input.conversationId === 'string' ? input.conversationId : undefined,
    },
    ...(deterministicOnly ? { deterministicOnly: true } : {}),
    ...(obj.mocked_ai_precompile_output
      ? { mocked_ai_precompile_output: obj.mocked_ai_precompile_output as AiPrecompileOutput }
      : {}),
    expected: obj.expected as FixtureExpected,
  };
}

/**
 * FixtureDiff - Structural diff between actual and expected fixture results.
 *
 * Walks expected.terminalArtifacts recursively. For each leaf path,
 * compares with actual.  A path is:
 *   - **matched** if both exist and are deep-equal.
 *   - **partial** if both exist and expected is a subset of actual
 *     (i.e. every key in expected matches in actual; extra actual keys
 *     are fine — "contains" semantics).
 *   - **missing** if expected has it and actual does not.
 *   - **extra** if actual has a top-level field that is in
 *     TerminalArtifacts but not pinned by expected AND non-empty.
 *
 * If expected.outcome is set, compare with actual and include the
 * result in matched or missing accordingly.
 */

import type { FixtureDiff, FixtureResult, FixtureExpected } from './FixtureTypes.js';
import type { TerminalArtifacts } from '../CompileContracts.js';

// ---------------------------------------------------------------------------
// deepEqual — strict equality for two values
// ---------------------------------------------------------------------------

function deepEqual(a: unknown, b: unknown): boolean {
  if (a === b) return true;
  if (a === null || b === null) return false;
  if (typeof a !== typeof b) return false;

  if (Array.isArray(a)) {
    if (!Array.isArray(b)) return false;
    if (a.length !== b.length) return false;
    return a.every((v, i) => deepEqual(v, b[i]));
  }

  if (typeof a === 'object') {
    const keysA = Object.keys(a as object);
    const keysB = Object.keys(b as object);
    if (keysA.length !== keysB.length) return false;
    return keysA.every((k) => deepEqual((a as Record<string, unknown>)[k], (b as Record<string, unknown>)[k]));
  }

  return false;
}

// ---------------------------------------------------------------------------
// expectedContainsActual — "contains" semantics: every key in expected
// must match in actual; extra keys in actual are fine.
// ---------------------------------------------------------------------------

function expectedContainsActual(expected: unknown, actual: unknown): boolean {
  if (expected === null || expected === undefined) return true;
  if (actual === null || actual === undefined) return false;

  // If expected is a primitive, compare strictly
  if (typeof expected !== 'object') {
    return deepEqual(expected, actual);
  }

  // If expected is an array, compare element-by-element with contains semantics
  if (Array.isArray(expected)) {
    if (!Array.isArray(actual)) return false;
    if (expected.length === 0) return true;
    if (actual.length === 0) return false;
    // Compare element-by-element: expected[i] must be contained in actual[i]
    const len = Math.min(expected.length, actual.length);
    for (let i = 0; i < len; i++) {
      if (!expectedContainsActual(expected[i], actual[i])) {
        return false;
      }
    }
    return true;
  }

  // expected is an object: every key must match in actual
  const expKeys = Object.keys(expected as object);
  for (const key of expKeys) {
    const expVal = (expected as Record<string, unknown>)[key];
    const actVal = (actual as Record<string, unknown>)[key];
    if (!expectedContainsActual(expVal, actVal)) {
      return false;
    }
  }
  return true;
}

// ---------------------------------------------------------------------------
// walkExpected — recursively walk expected.terminalArtifacts and compare
// ---------------------------------------------------------------------------

function walkExpected(
  expected: unknown,
  actual: unknown,
  path: string,
  matched: string[],
  partial: string[],
  missing: string[],
): void {
  // If expected is null/undefined, nothing to check at this path
  if (expected === null || expected === undefined) return;

  // If actual is null/undefined but expected is not, it's missing
  if (actual === null || actual === undefined) {
    missing.push(path);
    return;
  }

  // If expected is a primitive, compare strictly
  if (typeof expected !== 'object') {
    if (deepEqual(expected, actual)) {
      matched.push(path);
    } else {
      missing.push(path);
    }
    return;
  }

  // If expected is an array, compare element-by-element
  if (Array.isArray(expected)) {
    if (!Array.isArray(actual)) {
      missing.push(path);
      return;
    }
    if (expected.length === 0) {
      matched.push(path);
      return;
    }
    if (actual.length === 0) {
      missing.push(path);
      return;
    }
    // Compare element-by-element with contains semantics
    const len = Math.min(expected.length, actual.length);
    let allMatched = true;
    let hasPartial = false;
    for (let i = 0; i < len; i++) {
      const childPath = `${path}[${i}]`;
      const expVal = expected[i];
      const actVal = actual[i];

      walkExpected(expVal, actVal, childPath, matched, partial, missing);

      // Check if this child was matched or partial
      const lastMatched = matched[matched.length - 1];
      const lastPartial = partial.length > 0 ? partial[partial.length - 1] : undefined;

      if (lastMatched === childPath) {
        // matched — continue
      } else if (lastPartial === childPath) {
        hasPartial = true;
      } else {
        allMatched = false;
      }
    }

    if (allMatched && !hasPartial) {
      matched.push(path);
    } else if (hasPartial) {
      partial.push(path);
    }
    return;
  }

  // expected is an object — walk its keys
  const expKeys = Object.keys(expected as object);
  if (expKeys.length === 0) {
    // Empty object in expected — treat as matched if actual is also object-like
    matched.push(path);
    return;
  }

  // Check if actual contains all expected keys
  const actObj = actual as Record<string, unknown>;
  let allMatched = true;
  let hasPartial = false;

  for (const key of expKeys) {
    const childPath = `${path}.${key}`;
    const expVal = (expected as Record<string, unknown>)[key];
    const actVal = actObj[key];

    walkExpected(expVal, actVal, childPath, matched, partial, missing);

    // Check if this child was matched or partial
    const lastMatched = matched[matched.length - 1];
    const lastPartial = partial.length > 0 ? partial[partial.length - 1] : undefined;

    if (lastMatched === childPath) {
      // matched — continue
    } else if (lastPartial === childPath) {
      hasPartial = true;
    } else {
      allMatched = false;
    }
  }

  // If all children matched, this path is matched
  if (allMatched && !hasPartial) {
    matched.push(path);
  } else if (hasPartial) {
    partial.push(path);
  }
}

// ---------------------------------------------------------------------------
// findExtra — find top-level fields in actual that are not in expected
// ---------------------------------------------------------------------------

function findExtra(
  expected: Partial<TerminalArtifacts> | undefined,
  actual: TerminalArtifacts,
): string[] {
  const extra: string[] = [];
  const expectedKeys = new Set(expected ? Object.keys(expected) : []);

  for (const key of Object.keys(actual)) {
    if (!expectedKeys.has(key)) {
      const val = (actual as Record<string, unknown>)[key];
      // Only report non-empty extras
      if (val !== null && val !== undefined && !(Array.isArray(val) && val.length === 0)) {
        extra.push(key);
      }
    }
  }

  return extra;
}

// ---------------------------------------------------------------------------
// diffFixture — main entry point
// ---------------------------------------------------------------------------

export function diffFixture(actual: FixtureResult, expected: FixtureExpected): FixtureDiff {
  const matched: string[] = [];
  const partial: string[] = [];
  const missing: string[] = [];
  const extra: string[] = [];

  // Compare outcome if set
  if (expected.outcome !== undefined) {
    if (actual.outcome === expected.outcome) {
      matched.push('outcome');
    } else {
      missing.push('outcome');
    }
  }

  // Compare terminalArtifacts
  if (expected.terminalArtifacts !== undefined) {
    walkExpected(
      expected.terminalArtifacts,
      actual.terminalArtifacts,
      'terminalArtifacts',
      matched,
      partial,
      missing,
    );

    // Find extra top-level fields
    const extraFields = findExtra(expected.terminalArtifacts, actual.terminalArtifacts);
    extra.push(...extraFields);
  }

  return { matched, partial, missing, extra };
}

