/**
 * NounPhraseResolver — clause + verb → resolved noun-phrase hits.
 *
 * Given a Clause and its VerbMatch (if any), extracts noun-phrase candidates
 * from the post-verb text and resolves each against four registry tiers:
 *   1. labware-definition (exact match) → kind 'labware', confidence 1.0
 *   2. compound-class (exact match)     → kind 'compound', confidence 1.0
 *   3. ontology-term (case-insensitive substring) → kind 'ontology', confidence 0.7
 *   4. labware-instance (async substring) → kind 'labware-instance', confidence 0.6
 *
 * No fuzzy matching, no LLM calls. Pure async function because tier 4 is async.
 */

import type { Clause } from './TextSegmenter';
import type { VerbMatch } from './VerbMatcher';
import type { PromptMention } from '../../ai/promptMentions';
import type { MaterializedPromptTag } from './TaggerOutput';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ResolvedNoun {
  phrase: string;
  span: [number, number];
  kind: 'labware' | 'compound' | 'ontology' | 'labware-instance' | 'material' | 'unresolved';
  recordId?: string;
  confidence: number;
  source?: string;
  registryMatch?: FuzzyRegistryMatch;
}

export interface FuzzyRegistryMatch {
  distance: number;
  matchedKey: string;
  matchKind: 'exact' | 'normalized' | 'edit';
}

export interface NounResolverDeps {
  labwareDefinitionRegistry: {
    findByName: (name: string) => ({ recordId: string } & Partial<{ registryMatch: FuzzyRegistryMatch }>) | undefined;
  };
  compoundClassRegistry: {
    findByName: (name: string) => ({ recordId: string } & Partial<{ registryMatch: FuzzyRegistryMatch }>) | undefined;
  };
  ontologyTermRegistry: {
    searchLabel: (q: string) => Array<{ id: string; label: string; source: string }>;
  };
  labwareInstanceLookup: (hint: string) => Promise<Array<{ recordId: string; title: string }>>;
  /**
   * Optional map keyed by lowercased placeholder token (e.g. `__mention_0__`)
   * → PromptMention. When present, a phrase that matches a key is resolved
   * directly from the mention's id, bypassing the registry tiers.
   *
   * Wired by DeterministicPrecompilePass after substituting `[[kind:id|label]]`
   * tokens with placeholder strings prior to clause segmentation.
   */
  mentionLookup?: Map<string, PromptMention>;
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const STOPWORDS = new Set([
  'the', 'a', 'an', 'some', 'this', 'that', 'these', 'those',
  // Pronouns / fillers — when an entire post-split fragment is one of these
  // it carries no entity content (e.g. "transfer 50uL of it to ...").
  'it', 'them', 'they',
]);

// Add `of` to the split set so phrases like "well A1 of the 12-well reservoir"
// break into "well A1" + "the 12-well reservoir" — otherwise the labware
// reference is hidden inside a larger string that no registry can match.
const NP_SPLIT_RE = /,\s*|\s+and\s+|\s+to\s+|\s+from\s+|\s+into\s+|\s+onto\s+|\s+of\s+|\s+on\s+|\s+using\s+|\s+with\s+/i;
const PURE_NUMERIC_RE = /^\d+(\.\d+)?$/;
const LEADING_STOPWORD_RE = /^(?:the|a|an|some|this|that|these|those)\s+/i;
// Phrases that are *only* a well address (or row/col label) — these are
// extracted separately by ParameterGrammar and don't need entity resolution.
// Example: "well A1", "wells A1, A3", "row B", "column 3", "A1-A12".
const WELL_ONLY_RE =
  /^(?:wells?\s+)?[A-H]\d{1,2}(?:\s*[,–-]\s*[A-H]\d{1,2})*$/i;
const ROW_COL_ONLY_RE = /^(?:row|col|column)\s+[A-Z0-9]+$/i;
const WELL_REGION_ONLY_RE = /^(?:(?:each|every|all)\s+)?wells?\s+(?:in\s+)?(?:row\s+[A-H]|(?:col|column)\s+\d{1,2})$/i;
const DECK_SLOT_ONLY_RE = /^(?:deck\s+)?slot\s+[A-D][1-4]$/i;
const ROLE_LOCATION_ONLY_RE = /^(?:source|target|destination)\s+(?:location|position|slot|destination)$/i;
const INSTRUMENT_ONLY_RE = /^(?:(?:gemini\s+em|gemini)(?:\s+plate\s+reader)?|[a-z0-9][a-z0-9\s-]*(?:plate reader|reader|spectrophotometer|fluorometer|luminometer))$/i;
const INSTRUMENT_FRAGMENT_RE = /^(?:(?:gemini\s+em|gemini)(?:\s+plate\s+reader)?|[a-z0-9][a-z0-9\s-]*(?:plate reader|reader|spectrophotometer|fluorometer|luminometer))(?:\s+(?:in|with|at|as)\b.*)?$/i;
// Phrases that are *only* a quantity with a unit — volume, count, or duration.
// Captured by ParameterGrammar; treating them as unresolved nouns would
// falsely flag clauses with literal volumes/counts as residual.
const VOLUME_ONLY_RE = /^\d+(?:\.\d+)?\s*(?:[µμ]L|uL|microliters?|mL|ml|milliliters?|L|liters?)$/i;
const CONCENTRATION_ONLY_RE = /^\d+(?:\.\d+)?\s*(?:nM|uM|µM|μM|mM|M)$/i;
const LEADING_CONCENTRATION_RE = /^\d+(?:\.\d+)?\s*(?:nM|uM|µM|μM|mM|M)\s+/i;
const DURATION_ONLY_RE = /^\d+(?:\.\d+)?\s*(?:s|sec|seconds?|m|min|minutes?|h|hr|hours?|d|days?)$/i;
const COUNT_ONLY_RE = /^\d+\s*(?:cells?|copies|colonies)$/i;
// Tokenizer matching TextSegmenter's split set, used for fuzzy back-reference
// matching against mention labels.
const FUZZY_TOKEN_SPLIT_RE = /[\s,;:.\-—–"'()\[\]{}!?]+/;

// ---------------------------------------------------------------------------
// Phrase splitting
// ---------------------------------------------------------------------------

/**
 * Extract noun-phrase candidates from the clause text.
 *
 * If verbMatch is present, text is sliced to post-verb region.
 * Then split on commas, 'and', 'to', 'from', 'into', 'onto'.
 * Trim, drop empty / stopwords / pure numerics.
 *
 * Returns fragments with their spans relative to the original clause.
 */
function extractNounPhraseCandidates(
  clause: Clause,
  verbMatch: VerbMatch | undefined,
): Array<{ phrase: string; span: [number, number] }> {
  // Determine the text region to split
  const verbOffset = verbMatch ? verbMatch.span[1] - clause.span[0] : 0;
  const region = clause.text.slice(verbOffset);

  // Split on delimiter regex
  const fragments = region.split(NP_SPLIT_RE);

  const results: Array<{ phrase: string; span: [number, number] }> = [];

  for (const frag of fragments) {
    let trimmed = frag.trim();
    if (trimmed.length === 0) continue;

    // Compute span using the un-stripped form (so highlights line up with
    // the user's original text) before we strip leading stopwords for
    // resolution purposes.
    const regionStart = clause.text.indexOf(trimmed, verbOffset);
    if (regionStart === -1) continue;

    const spanStart = regionStart + clause.span[0];
    const spanEnd = spanStart + trimmed.length;

    // Strip a leading determiner ("the 12-well reservoir" → "12-well reservoir")
    // so registry/mention lookups see the actual entity tokens.
    trimmed = trimmed.replace(LEADING_STOPWORD_RE, '');
    // Strip a leading concentration ("1mM clofibrate" → "clofibrate").
    // Concentrations are event parameters, while the remaining phrase is the
    // entity that should resolve against compound/material registries.
    trimmed = trimmed.replace(LEADING_CONCENTRATION_RE, '');
    if (trimmed.length === 0) continue;

    // Drop single stopwords
    if (STOPWORDS.has(trimmed.toLowerCase())) continue;

    // Drop pure numerics
    if (PURE_NUMERIC_RE.test(trimmed)) continue;

    // Drop phrases that are purely parameters (well addresses, volumes,
    // durations, counts). Those are extracted elsewhere by ParameterGrammar
    // and counting them as unresolved noun phrases would falsely flag the
    // clause as residual.
    if (
      WELL_ONLY_RE.test(trimmed) ||
      ROW_COL_ONLY_RE.test(trimmed) ||
      WELL_REGION_ONLY_RE.test(trimmed) ||
      DECK_SLOT_ONLY_RE.test(trimmed) ||
      ROLE_LOCATION_ONLY_RE.test(trimmed) ||
      INSTRUMENT_ONLY_RE.test(trimmed) ||
      INSTRUMENT_FRAGMENT_RE.test(trimmed) ||
      VOLUME_ONLY_RE.test(trimmed) ||
      CONCENTRATION_ONLY_RE.test(trimmed) ||
      DURATION_ONLY_RE.test(trimmed) ||
      COUNT_ONLY_RE.test(trimmed)
    ) continue;

    results.push({ phrase: trimmed, span: [spanStart, spanEnd] });
  }

  return results;
}

// ---------------------------------------------------------------------------
// Resolution
// ---------------------------------------------------------------------------

/**
 * Resolve a single noun-phrase candidate against the four registry tiers.
 * Returns the first hit or 'unresolved' (without span — caller adds it).
 */
async function resolveOne(
  phrase: string,
  deps: NounResolverDeps,
): Promise<Omit<ResolvedNoun, 'span'>> {
  // Tier 0: mention placeholder match. Phrases that came from `[[kind:id|label]]`
  // tokens are pre-resolved by the user — skip the registry tiers. We also scan
  // for an embedded placeholder because NP_SPLIT keeps surrounding modifiers
  // (e.g. `1000uL of __mention_2__`) attached to the placeholder.
  if (deps.mentionLookup) {
    const lower = phrase.toLowerCase();
    let hit = deps.mentionLookup.get(lower);
    if (!hit) {
      const embedded = lower.match(/__(?:input_)?mention_\d+__/);
      if (embedded) hit = deps.mentionLookup.get(embedded[0]);
    }
    if (hit && hit.id) {
      if (hit.type === 'labware') {
        return {
          phrase: hit.label || phrase,
          kind: isRuntimeLabwareMention(hit) ? 'labware-instance' : 'labware',
          recordId: hit.id,
          confidence: 1.0,
          source: 'mention',
        };
      }
      if (hit.type === 'material') {
        return { phrase: hit.label || phrase, kind: 'material', recordId: hit.id, confidence: 1.0, ...(hit.entityKind ? { source: hit.entityKind } : {}) };
      }
      // selection/protocol mentions don't map to noun-phrase semantics here.
    }

    const fuzzyMention = resolveFuzzyMention(phrase, deps.mentionLookup);
    if (fuzzyMention) return fuzzyMention;
  }

  // Tier 1: labware-definition exact match
  const lw = deps.labwareDefinitionRegistry.findByName(phrase);
  if (lw) {
    return {
      phrase,
      kind: 'labware',
      recordId: lw.recordId,
      confidence: 1.0,
      ...(lw.registryMatch ? { registryMatch: lw.registryMatch } : {}),
    };
  }

  // Tier 2: compound-class exact match
  const cp = deps.compoundClassRegistry.findByName(phrase);
  if (cp) {
    return {
      phrase,
      kind: 'compound',
      recordId: cp.recordId,
      confidence: 1.0,
      ...(cp.registryMatch ? { registryMatch: cp.registryMatch } : {}),
    };
  }

  // Tier 3: ontology-term case-insensitive substring
  const ontHits = deps.ontologyTermRegistry.searchLabel(phrase);
  if (ontHits.length > 0) {
    const first = ontHits[0]!;
    return {
      phrase,
      kind: 'ontology',
      recordId: first.id,
      source: first.source,
      confidence: 0.7,
    };
  }

  // Tier 4: labware-instance async lookup
  const instHits = await deps.labwareInstanceLookup(phrase);
  if (instHits.length > 0) {
    const first = instHits[0]!;
    return {
      phrase,
      kind: 'labware-instance',
      recordId: first.recordId,
      confidence: 0.6,
    };
  }

  const fuzzyMention = resolveFuzzyMention(phrase, deps.mentionLookup);
  if (fuzzyMention) return fuzzyMention;

  // No hit → unresolved
  return { phrase, kind: 'unresolved', confidence: 0 };
}

function tokenize(text: string): Set<string> {
  const out = new Set<string>();
  for (const t of text.toLowerCase().split(FUZZY_TOKEN_SPLIT_RE)) {
    if (t.length > 1 && !STOPWORDS.has(t)) out.add(t);
  }
  return out;
}

function isRuntimeLabwareMention(mention: PromptMention): boolean {
  return typeof mention.id === 'string' && mention.id.startsWith('lw-');
}

function resolveFuzzyMention(
  phrase: string,
  mentionLookup: Map<string, PromptMention> | undefined,
): Omit<ResolvedNoun, 'span'> | undefined {
  if (!mentionLookup || mentionLookup.size === 0) return undefined;

  const phraseTokens = tokenize(phrase);
  if (phraseTokens.size === 0) return undefined;

  let bestScore = 0;
  let bestMention: PromptMention | undefined;
  for (const mention of mentionLookup.values()) {
    if (!mention.id) continue;
    const labelTokens = tokenize(mention.label);
    if (labelTokens.size === 0) continue;
    let overlap = 0;
    for (const t of phraseTokens) if (labelTokens.has(t)) overlap++;
    if (overlap === 0) continue;
    const score = overlap / Math.max(phraseTokens.size, labelTokens.size);
    if (score > bestScore) {
      bestScore = score;
      bestMention = mention;
    }
  }

  // Threshold: require at least ~25% token overlap so generic words like
  // "plate" alone don't link to the wrong labware.
  if (!bestMention || bestScore < 0.25) return undefined;

  if (bestMention.type === 'labware') {
    return {
      phrase,
      kind: isRuntimeLabwareMention(bestMention) ? 'labware-instance' : 'labware',
      recordId: bestMention.id!,
      confidence: 0.5,
      source: 'mention-fuzzy',
    };
  }
  if (bestMention.type === 'material') {
    return {
      phrase,
      kind: 'material',
      recordId: bestMention.id!,
      confidence: 0.5,
      source: bestMention.entityKind ?? 'mention-fuzzy',
    };
  }

  return undefined;
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Resolve noun phrases in a clause.
 *
 * @param clause  — the clause from TextSegmenter
 * @param verbMatch — the matched verb (if any)
 * @param deps — registry lookups
 * @returns resolved noun phrases, in order of appearance
 */
export async function resolveNounPhrases(
  clause: Clause,
  verbMatch: VerbMatch | undefined,
  deps: NounResolverDeps,
): Promise<ResolvedNoun[]> {
  const candidates = extractNounPhraseCandidates(clause, verbMatch);

  const resolved: ResolvedNoun[] = [];

  for (const { phrase, span } of candidates) {
    const result = await resolveOne(phrase, deps);
    resolved.push({ ...result, span });
  }

  return resolved;
}

export async function resolveNounPhrasesFromTags(
  tags: MaterializedPromptTag[],
  deps: NounResolverDeps,
): Promise<ResolvedNoun[]> {
  const resolved: ResolvedNoun[] = [];

  for (const tag of tags) {
    if (tag.kind === 'mention') {
      const mention = resolveMentionTag(tag);
      if (mention) resolved.push(mention);
      continue;
    }

    if (tag.kind !== 'noun_phrase') continue;

    const result = await resolveOne(tag.text, deps);
    const candidateSource = tag.candidateKinds && tag.candidateKinds.length > 0
      ? `tag:${tag.candidateKinds.join(',')}`
      : undefined;
    resolved.push({
      ...result,
      span: tag.span,
      ...(result.kind === 'unresolved' && candidateSource ? { source: candidateSource } : {}),
    });
  }

  return resolved.sort((a, b) => a.span[0] - b.span[0]);
}

function resolveMentionTag(tag: MaterializedPromptTag): ResolvedNoun | undefined {
  if (!tag.id) return undefined;

  const mentionKind = tag.mentionKind?.toLowerCase();
  if (mentionKind === 'labware' || tag.id.startsWith('lw-') || tag.id.startsWith('lbw-') || tag.id.startsWith('def:')) {
    return {
      phrase: tag.text,
      span: tag.span,
      kind: tag.id.startsWith('lw-') ? 'labware-instance' : 'labware',
      recordId: tag.id,
      confidence: 1.0,
      source: 'mention',
    };
  }

  if (
    mentionKind === 'material' ||
    mentionKind === 'aliquot' ||
    mentionKind === 'material-spec' ||
    mentionKind === 'compound'
  ) {
    return {
      phrase: tag.text,
      span: tag.span,
      kind: 'material',
      recordId: tag.id,
      confidence: 1.0,
      source: mentionKind,
    };
  }

  return undefined;
}

/**
 * Fix-it fixture discovery test.
 *
 * Scans this directory for `spec-fix-*.yaml` files and runs each one
 * through the deterministic precompile via FixtureRunner. New fix-it
 * sessions land their failing-prompt fixture here as part of the spec
 * synthesis step; the coder agent must make all of them pass before
 * its patch is committed.
 *
 * Run a specific fixture with:
 *   npx vitest run server/src/compiler/pipeline/fixtures/FixItFixtures.test.ts -t '<fixture-name>'
 */

import { describe, expect, it } from 'vitest';
import { readdirSync, readFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { parseFixture } from './FixtureTypes.js';
import { runFixture } from './FixtureRunner.js';
import { diffFixture } from './FixtureDiff.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const SPEC_FIX_PATTERN = /^spec-fix-.+\.yaml$/;

const fixtureFiles = readdirSync(__dirname)
  .filter((name) => SPEC_FIX_PATTERN.test(name))
  .sort();

// If there are no fix-it fixtures yet, the suite still defines a single test
// so it's discoverable in CI output. (vitest dislikes empty describe blocks.)
describe('FixItFixtures', () => {
  if (fixtureFiles.length === 0) {
    it('no spec-fix-*.yaml fixtures yet (this is fine; nothing to run)', () => {
      expect(true).toBe(true);
    });
    return;
  }

  for (const fileName of fixtureFiles) {
    const yamlText = readFileSync(join(__dirname, fileName), 'utf-8');
    const fixture = parseFixture(yamlText);

    // The test name == fixture name so the coder agent can target a single
    // fixture from the spec via `-t '<fixture-name>'`.
    it(fixture.name, async () => {
      const result = await runFixture(fixture);
      const diff = diffFixture(result, fixture.expected);
      // Missing keys = expected fields the actual output doesn't have.
      // Treat any missing as a hard fail; partial/extra are advisory.
      expect(diff.missing, `missing keys: ${diff.missing.join(', ')}`).toEqual([]);
    });
  }
});

/**
 * FixtureRunner - Runs a compile pipeline with a mocked LLM.
 *
 * The runner builds a mock LlmClient that returns the fixture's pinned
 * ai_precompile output verbatim, then invokes runChatbotCompile and
 * collects the actual TerminalArtifacts.
 */

import type { LlmClient, AiPrecompileOutput } from '../passes/ChatbotCompilePasses.js';
import type { CompletionRequest, CompletionResponse } from '../../../ai/types.js';
import type { RunChatbotCompileArgs, RunChatbotCompileResult } from '../../../ai/runChatbotCompile.js';
import { runChatbotCompile } from '../../../ai/runChatbotCompile.js';
import type { Fixture, FixtureResult } from './FixtureTypes.js';
import type { ExtractionRunnerService, RunExtractionServiceArgs } from '../../../extract/ExtractionRunnerService.js';
import type { ExtractionDraftBody } from '../../../extract/ExtractionDraftBuilder.js';
import type { FileAttachment } from '../../../ai/types.js';

// Ensure pattern expanders are registered (side-effect import)
import '../../../compiler/patterns/index.js';

// ---------------------------------------------------------------------------
// buildTestDeps — minimal stubs for non-LLM dependencies
// ---------------------------------------------------------------------------

/**
 * Build a minimal ExtractionRunnerService stub that returns empty results.
 */
function buildTestExtractionService(): ExtractionRunnerService {
  return {
    run: async (_req: RunExtractionServiceArgs): Promise<ExtractionDraftBody> => ({
      target_kind: _req.target_kind,
      source: _req.source,
      candidates: [],
      diagnostics: [],
    }),
  } as unknown as ExtractionRunnerService;
}

/**
 * Build a minimal searchLabwareByHint stub that returns no matches.
 */
function buildTestSearchLabwareByHint() {
  return async (_hint: string): Promise<Array<{ recordId: string; title: string }>> => [];
}

// ---------------------------------------------------------------------------
// buildMockLlmClient — create an LlmClient that returns the pinned output
// ---------------------------------------------------------------------------

function buildMockLlmClient(mockedOutput: AiPrecompileOutput): LlmClient {
  return {
    complete: async (_req: CompletionRequest): Promise<CompletionResponse> => {
      const content = JSON.stringify(mockedOutput);
      return {
        id: 'fixture-mock',
        choices: [
          {
            index: 0,
            message: { role: 'assistant', content },
            finish_reason: 'stop',
          },
        ],
        usage: { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 },
      };
    },
  };
}

// ---------------------------------------------------------------------------
// runFixture — execute a fixture with mocked LLM
// ---------------------------------------------------------------------------

export async function runFixture(
  fixture: Fixture,
  opts?: {
    deps?: Partial<RunChatbotCompileArgs['deps']>;
    conversationId?: string;
  },
): Promise<FixtureResult> {
  // Deterministic-only fixtures don't have a mocked LLM output — the
  // deterministic precompile is the unit under test, so the LLM is fully
  // bypassed. The fixture validator already enforces that mocked_ai_precompile_output
  // is present for non-deterministic fixtures.
  const deterministicOnly = fixture.deterministicOnly === true;
  const llmClient: LlmClient | null = opts?.deps?.llmClient
    ?? (deterministicOnly
      ? null
      : buildMockLlmClient(fixture.mocked_ai_precompile_output!));

  const attachments = fixture.input.attachments?.map((a) => ({
    name: a.filename,
    mime_type: a.mimeType,
    content: a.content,
  }));
  const conversationId = opts?.conversationId ?? fixture.input.conversationId;

  const args: RunChatbotCompileArgs = {
    prompt: fixture.input.prompt,
    ...(attachments ? { attachments } : {}),
    ...(conversationId ? { conversationId } : {}),
    ...(deterministicOnly ? { deterministicOnly: true } : {}),
    deps: {
      extractionService: buildTestExtractionService(),
      llmClient,
      searchLabwareByHint: opts?.deps?.searchLabwareByHint ?? buildTestSearchLabwareByHint(),
      ...(opts?.deps?.labStateCache ? { labStateCache: opts.deps.labStateCache } : {}),
    },
  };

  const result: RunChatbotCompileResult = await runChatbotCompile(args);

  return {
    outcome: result.outcome,
    terminalArtifacts: result.terminalArtifacts,
    raw: result,
  };
}

/**
 * FixtureTypes - Type definitions and YAML parser for compile-pipeline fixtures.
 *
 * A fixture pins both the input (prompt, attachments, history) and the
 * expected output (outcome, terminalArtifacts) of a compile run.  The
 * mocked_ai_precompile_output field lets the runner bypass the LLM
 * entirely and feed a deterministic candidate-event graph into the
 * pipeline.
 */

import { parse as parseYaml } from 'yaml';
import type { TerminalArtifacts, CompileOutcome } from '../CompileContracts.js';
import type { AiPrecompileOutput } from '../passes/ChatbotCompilePasses.js';

// ---------------------------------------------------------------------------
// FixtureInput — what the user sends to the compile
// ---------------------------------------------------------------------------

export interface FixtureInput {
  prompt: string;
  attachments?: Array<{ filename: string; mimeType: string; content: string }>;
  history?: Array<{ role: 'user' | 'assistant'; content: string }>;
  conversationId?: string;
}

// ---------------------------------------------------------------------------
// FixtureExpected — what we assert the compile produced
// ---------------------------------------------------------------------------

export interface FixtureExpected {
  outcome?: CompileOutcome;
  terminalArtifacts?: Partial<TerminalArtifacts>;
}

// ---------------------------------------------------------------------------
// Fixture — the full fixture document
// ---------------------------------------------------------------------------

export interface Fixture {
  name: string;
  description?: string;
  input: FixtureInput;
  /**
   * Replaces the LLM-backed ai_precompile pass with these candidate
   * events/labwares. Required when `deterministicOnly` is false or absent —
   * skipped when `deterministicOnly: true` (the deterministic precompile
   * does the work).
   */
  mocked_ai_precompile_output?: AiPrecompileOutput;
  /**
   * When true, the runner sets deterministicOnly on runChatbotCompile so the
   * deterministic precompile is the only source of candidate events/labwares.
   * Used by event-editor fix-it fixtures that capture "this prompt should
   * produce that ghost preview without any LLM in the loop."
   */
  deterministicOnly?: boolean;
  expected: FixtureExpected;
}

// ---------------------------------------------------------------------------
// FixtureResult — what the runner produces
// ---------------------------------------------------------------------------

export interface FixtureResult {
  outcome: CompileOutcome;
  terminalArtifacts: TerminalArtifacts;
  raw: unknown; // full RunChatbotCompileResult for debugging
}

// ---------------------------------------------------------------------------
// FixtureDiff — structural comparison result
// ---------------------------------------------------------------------------

export interface FixtureDiff {
  matched: string[];
  partial: string[];
  missing: string[];
  extra: string[];
}

// ---------------------------------------------------------------------------
// parseFixture — load a Fixture from YAML text
// ---------------------------------------------------------------------------

/**
 * Parse a YAML string into a Fixture, performing basic shape validation.
 *
 * @param yamlText — raw YAML document
 * @returns the parsed Fixture
 * @throws Error if the YAML is invalid or the shape doesn't match
 */
export function parseFixture(yamlText: string): Fixture {
  const raw = parseYaml(yamlText);

  if (typeof raw !== 'object' || raw === null) {
    throw new Error('Fixture YAML must be a mapping');
  }

  const obj = raw as Record<string, unknown>;

  // Validate required fields
  if (typeof obj.name !== 'string' || obj.name.trim() === '') {
    throw new Error('Fixture must have a non-empty "name" string');
  }

  if (typeof obj.input !== 'object' || obj.input === null) {
    throw new Error('Fixture must have an "input" mapping');
  }

  const input = obj.input as Record<string, unknown>;
  if (typeof input.prompt !== 'string' || input.prompt.trim() === '') {
    throw new Error('Fixture input must have a non-empty "prompt" string');
  }

  const deterministicOnly = obj.deterministicOnly === true;

  if (!deterministicOnly) {
    if (typeof obj.mocked_ai_precompile_output !== 'object' || obj.mocked_ai_precompile_output === null) {
      throw new Error('Fixture must have a "mocked_ai_precompile_output" mapping (omit only when deterministicOnly: true)');
    }
  }

  if (typeof obj.expected !== 'object' || obj.expected === null) {
    throw new Error('Fixture must have an "expected" mapping');
  }

  return {
    name: obj.name as string,
    description: typeof obj.description === 'string' ? obj.description : undefined,
    input: {
      prompt: input.prompt as string,
      attachments: Array.isArray(input.attachments)
        ? (input.attachments as Array<Record<string, unknown>>).map((a) => ({
            filename: (a.filename as string) ?? '',
            mimeType: (a.mimeType as string) ?? '',
            content: (a.content as string) ?? '',
          }))
        : undefined,
      history: Array.isArray(input.history)
        ? (input.history as Array<Record<string, unknown>>).map((h) => ({
            role: (h.role as 'user' | 'assistant') ?? 'user',
            content: (h.content as string) ?? '',
          }))
        : undefined,
      conversationId: typeof input.conversationId === 'string' ? input.conversationId : undefined,
    },
    ...(deterministicOnly ? { deterministicOnly: true } : {}),
    ...(obj.mocked_ai_precompile_output
      ? { mocked_ai_precompile_output: obj.mocked_ai_precompile_output as AiPrecompileOutput }
      : {}),
    expected: obj.expected as FixtureExpected,
  };
}

/**
 * FixtureDiff - Structural diff between actual and expected fixture results.
 *
 * Walks expected.terminalArtifacts recursively. For each leaf path,
 * compares with actual.  A path is:
 *   - **matched** if both exist and are deep-equal.
 *   - **partial** if both exist and expected is a subset of actual
 *     (i.e. every key in expected matches in actual; extra actual keys
 *     are fine — "contains" semantics).
 *   - **missing** if expected has it and actual does not.
 *   - **extra** if actual has a top-level field that is in
 *     TerminalArtifacts but not pinned by expected AND non-empty.
 *
 * If expected.outcome is set, compare with actual and include the
 * result in matched or missing accordingly.
 */

import type { FixtureDiff, FixtureResult, FixtureExpected } from './FixtureTypes.js';
import type { TerminalArtifacts } from '../CompileContracts.js';

// ---------------------------------------------------------------------------
// deepEqual — strict equality for two values
// ---------------------------------------------------------------------------

function deepEqual(a: unknown, b: unknown): boolean {
  if (a === b) return true;
  if (a === null || b === null) return false;
  if (typeof a !== typeof b) return false;

  if (Array.isArray(a)) {
    if (!Array.isArray(b)) return false;
    if (a.length !== b.length) return false;
    return a.every((v, i) => deepEqual(v, b[i]));
  }

  if (typeof a === 'object') {
    const keysA = Object.keys(a as object);
    const keysB = Object.keys(b as object);
    if (keysA.length !== keysB.length) return false;
    return keysA.every((k) => deepEqual((a as Record<string, unknown>)[k], (b as Record<string, unknown>)[k]));
  }

  return false;
}

// ---------------------------------------------------------------------------
// expectedContainsActual — "contains" semantics: every key in expected
// must match in actual; extra keys in actual are fine.
// ---------------------------------------------------------------------------

function expectedContainsActual(expected: unknown, actual: unknown): boolean {
  if (expected === null || expected === undefined) return true;
  if (actual === null || actual === undefined) return false;

  // If expected is a primitive, compare strictly
  if (typeof expected !== 'object') {
    return deepEqual(expected, actual);
  }

  // If expected is an array, compare element-by-element with contains semantics
  if (Array.isArray(expected)) {
    if (!Array.isArray(actual)) return false;
    if (expected.length === 0) return true;
    if (actual.length === 0) return false;
    // Compare element-by-element: expected[i] must be contained in actual[i]
    const len = Math.min(expected.length, actual.length);
    for (let i = 0; i < len; i++) {
      if (!expectedContainsActual(expected[i], actual[i])) {
        return false;
      }
    }
    return true;
  }

  // expected is an object: every key must match in actual
  const expKeys = Object.keys(expected as object);
  for (const key of expKeys) {
    const expVal = (expected as Record<string, unknown>)[key];
    const actVal = (actual as Record<string, unknown>)[key];
    if (!expectedContainsActual(expVal, actVal)) {
      return false;
    }
  }
  return true;
}

// ---------------------------------------------------------------------------
// walkExpected — recursively walk expected.terminalArtifacts and compare
// ---------------------------------------------------------------------------

function walkExpected(
  expected: unknown,
  actual: unknown,
  path: string,
  matched: string[],
  partial: string[],
  missing: string[],
): void {
  // If expected is null/undefined, nothing to check at this path
  if (expected === null || expected === undefined) return;

  // If actual is null/undefined but expected is not, it's missing
  if (actual === null || actual === undefined) {
    missing.push(path);
    return;
  }

  // If expected is a primitive, compare strictly
  if (typeof expected !== 'object') {
    if (deepEqual(expected, actual)) {
      matched.push(path);
    } else {
      missing.push(path);
    }
    return;
  }

  // If expected is an array, compare element-by-element
  if (Array.isArray(expected)) {
    if (!Array.isArray(actual)) {
      missing.push(path);
      return;
    }
    if (expected.length === 0) {
      matched.push(path);
      return;
    }
    if (actual.length === 0) {
      missing.push(path);
      return;
    }
    // Compare element-by-element with contains semantics
    const len = Math.min(expected.length, actual.length);
    let allMatched = true;
    let hasPartial = false;
    for (let i = 0; i < len; i++) {
      const childPath = `${path}[${i}]`;
      const expVal = expected[i];
      const actVal = actual[i];

      walkExpected(expVal, actVal, childPath, matched, partial, missing);

      // Check if this child was matched or partial
      const lastMatched = matched[matched.length - 1];
      const lastPartial = partial.length > 0 ? partial[partial.length - 1] : undefined;

      if (lastMatched === childPath) {
        // matched — continue
      } else if (lastPartial === childPath) {
        hasPartial = true;
      } else {
        allMatched = false;
      }
    }

    if (allMatched && !hasPartial) {
      matched.push(path);
    } else if (hasPartial) {
      partial.push(path);
    }
    return;
  }

  // expected is an object — walk its keys
  const expKeys = Object.keys(expected as object);
  if (expKeys.length === 0) {
    // Empty object in expected — treat as matched if actual is also object-like
    matched.push(path);
    return;
  }

  // Check if actual contains all expected keys
  const actObj = actual as Record<string, unknown>;
  let allMatched = true;
  let hasPartial = false;

  for (const key of expKeys) {
    const childPath = `${path}.${key}`;
    const expVal = (expected as Record<string, unknown>)[key];
    const actVal = actObj[key];

    walkExpected(expVal, actVal, childPath, matched, partial, missing);

    // Check if this child was matched or partial
    const lastMatched = matched[matched.length - 1];
    const lastPartial = partial.length > 0 ? partial[partial.length - 1] : undefined;

    if (lastMatched === childPath) {
      // matched — continue
    } else if (lastPartial === childPath) {
      hasPartial = true;
    } else {
      allMatched = false;
    }
  }

  // If all children matched, this path is matched
  if (allMatched && !hasPartial) {
    matched.push(path);
  } else if (hasPartial) {
    partial.push(path);
  }
}

// ---------------------------------------------------------------------------
// findExtra — find top-level fields in actual that are not in expected
// ---------------------------------------------------------------------------

function findExtra(
  expected: Partial<TerminalArtifacts> | undefined,
  actual: TerminalArtifacts,
): string[] {
  const extra: string[] = [];
  const expectedKeys = new Set(expected ? Object.keys(expected) : []);

  for (const key of Object.keys(actual)) {
    if (!expectedKeys.has(key)) {
      const val = (actual as Record<string, unknown>)[key];
      // Only report non-empty extras
      if (val !== null && val !== undefined && !(Array.isArray(val) && val.length === 0)) {
        extra.push(key);
      }
    }
  }

  return extra;
}

// ---------------------------------------------------------------------------
// diffFixture — main entry point
// ---------------------------------------------------------------------------

export function diffFixture(actual: FixtureResult, expected: FixtureExpected): FixtureDiff {
  const matched: string[] = [];
  const partial: string[] = [];
  const missing: string[] = [];
  const extra: string[] = [];

  // Compare outcome if set
  if (expected.outcome !== undefined) {
    if (actual.outcome === expected.outcome) {
      matched.push('outcome');
    } else {
      missing.push('outcome');
    }
  }

  // Compare terminalArtifacts
  if (expected.terminalArtifacts !== undefined) {
    walkExpected(
      expected.terminalArtifacts,
      actual.terminalArtifacts,
      'terminalArtifacts',
      matched,
      partial,
      missing,
    );

    // Find extra top-level fields
    const extraFields = findExtra(expected.terminalArtifacts, actual.terminalArtifacts);
    extra.push(...extraFields);
  }

  return { matched, partial, missing, extra };
}

